        public static void InitObs()
        {
            for (int ifrom = 0; ifrom < Square_NB; ifrom++)
            {
                for (int ito = 0; ito < Square_NB; ito++)
                {
                    Direction d = Adirec[ifrom, ito];
                    BitBoard bb = 0;
                    switch (d)
                    {
                        case Direction.Direc_Rank_L2r:
                            if (FileTable[ifrom] == File.File9)
                                continue;
                            int dist = Math.Abs(ifrom - ito);
                            if (dist >= 2)
                            {
                                for (int i = 0; i < dist - 1; i++)
                                {
                                    int delta = (i + 1) * (int)Direction.Direc_Rank_L2r;
                                    bb |= ABB_Mask[ifrom + delta];
                                }
                                ABB_Obstacles[ifrom, ito] = bb;
                            }
                            break;
                        case Direction.Direc_Rank_R2l:
                            if (FileTable[ifrom] == File.File1)
                                continue;
                            dist = Math.Abs(ifrom - ito);
                            if (dist >= 2)
                            {
                                for (int i = 0; i < dist - 1; i++)
                                {
                                    int delta = (i + 1) * (int)Direction.Direc_Rank_R2l;
                                    bb |= ABB_Mask[ifrom + delta];
                                }
                                ABB_Obstacles[ifrom, ito] = bb;
                            }
                            break;
                        case Direction.Direc_File_U2d:
                            if (RankTable[ifrom] == Rank.Rank9)
                                continue;
                            dist = Math.Abs(ifrom - ito);
                            if (dist >= 18)
                            {
                                dist /= 9;
                                for (int i = 0; i < dist - 1; i++)
                                {
                                    int delta = (i + 1) * (int)Direction.Direc_File_U2d;
                                    bb |= ABB_Mask[ifrom + delta];
                                }
                                ABB_Obstacles[ifrom, ito] = bb;
                            }
                            break;
                        case Direction.Direc_File_D2u:
                            if (RankTable[ifrom] == Rank.Rank1)
                                continue;
                            dist = Math.Abs(ifrom - ito);
                            if (dist >= 18)
                            {
                                dist /= 9;
                                for (int i = 0; i < dist - 1; i++)
                                {
                                    int delta = (i + 1) * (int)Direction.Direc_File_D2u;
                                    bb |= ABB_Mask[ifrom + delta];
                                }
                                ABB_Obstacles[ifrom, ito] = bb;
                            }
                            break;
                        case Direction.Direc_Diag1_U2d:
                            if (FileTable[ifrom] == File.File1 || RankTable[ifrom] == Rank.Rank9)
                                continue;
                            dist = Math.Abs(ifrom - ito);
                            if (dist >= 16)
                            {
                                dist /= 8;
                                for (int i = 0; i < dist - 1; i++)
                                {
                                    int delta = (i + 1) * (int)Direction.Direc_Diag1_U2d;
                                    bb |= ABB_Mask[ifrom + delta];
                                }
                                ABB_Obstacles[ifrom, ito] = bb;
                            }
                            break;
                        case Direction.Direc_Diag1_D2u:
                            if (FileTable[ifrom] == File.File9 || RankTable[ifrom] == Rank.Rank1)
                                continue;
                            dist = Math.Abs(ifrom - ito);
                            if (dist >= 16)
                            {
                                dist /= 8;
                                for (int i = 0; i < dist - 1; i++)
                                {
                                    int delta = (i + 1) * (int)Direction.Direc_Diag1_D2u;
                                    bb |= ABB_Mask[ifrom + delta];
                                }
                                ABB_Obstacles[ifrom, ito] = bb;
                            }
                            break;
                        case Direction.Direc_Diag2_U2d:
                            if (FileTable[ifrom] == File.File9 || RankTable[ifrom] == Rank.Rank9)
                                continue;
                            dist = Math.Abs(ifrom - ito);
                            if (dist >= 20)
                            {
                                dist /= 10;
                                for (int i = 0; i < dist - 1; i++)
                                {
                                    int delta = (i + 1) * (int)Direction.Direc_Diag2_U2d;
                                    bb |= ABB_Mask[ifrom + delta];
                                }
                                ABB_Obstacles[ifrom, ito] = bb;
                            }
                            break;
                        case Direction.Direc_Diag2_D2u:
                            if (FileTable[ifrom] == File.File1 || RankTable[ifrom] == Rank.Rank1)
                                continue;
                            dist = Math.Abs(ifrom - ito);
                            if (dist >= 20)
                            {
                                dist /= 10;
                                for (int i = 0; i < dist - 1; i++)
                                {
                                    int delta = (i + 1) * (int)Direction.Direc_Diag2_D2u;
                                    bb |= ABB_Mask[ifrom + delta];
                                }
                                ABB_Obstacles[ifrom, ito] = bb;
                            }
                            break;
                    }
                }
            }
        }

        public static void InitPieceAttacks()
        {
            int color = (int)Color.Black;
            for (int pc = (int)Piece.Pawn; pc < Piece_NB; pc++)
            {
                for (int ifrom = 0; ifrom < Square_NB; ifrom++)
                {
                    switch (pc)
                    {
                        case (int)Piece.Pawn:
                            SetAttacks(color, pc, ifrom, ifrom + (int)Direction.Direc_File_D2u);
                            break;
                        case (int)Piece.Knight:
                            SetAttacks(color, pc, ifrom, ifrom + (int)Direction.Direc_Knight_L_D2u);
                            SetAttacks(color, pc, ifrom, ifrom + (int)Direction.Direc_Knight_R_D2u);
                            break;
                        case (int)Piece.Silver:
                            SetAttacks(color, pc, ifrom, ifrom + (int)Direction.Direc_File_D2u);
                            SetAttacks(color, pc, ifrom, ifrom + (int)Direction.Direc_Diag1_D2u);
                            SetAttacks(color, pc, ifrom, ifrom + (int)Direction.Direc_Diag2_D2u);
                            SetAttacks(color, pc, ifrom, ifrom + (int)Direction.Direc_Diag1_U2d);
                            SetAttacks(color, pc, ifrom, ifrom + (int)Direction.Direc_Diag2_U2d);
                            break;
                        case (int)Piece.Gold:
                        case (int)Piece.Pro_Pawn:
                        case (int)Piece.Pro_Lance:
                        case (int)Piece.Pro_Knight:
                        case (int)Piece.Pro_Silver:
                            SetAttacks(color, pc, ifrom, ifrom + (int)Direction.Direc_File_D2u);
                            SetAttacks(color, pc, ifrom, ifrom + (int)Direction.Direc_File_U2d);
                            SetAttacks(color, pc, ifrom, ifrom + (int)Direction.Direc_Diag1_D2u);
                            SetAttacks(color, pc, ifrom, ifrom + (int)Direction.Direc_Diag2_D2u);
                            SetAttacks(color, pc, ifrom, ifrom + (int)Direction.Direc_Rank_L2r);
                            SetAttacks(color, pc, ifrom, ifrom + (int)Direction.Direc_Rank_R2l);
                            break;
                        case (int)Piece.King:
                            SetAttacks(color, pc, ifrom, ifrom + (int)Direction.Direc_File_D2u);
                            SetAttacks(color, pc, ifrom, ifrom + (int)Direction.Direc_File_U2d);
                            SetAttacks(color, pc, ifrom, ifrom + (int)Direction.Direc_Diag1_D2u);
                            SetAttacks(color, pc, ifrom, ifrom + (int)Direction.Direc_Diag2_D2u);
                            SetAttacks(color, pc, ifrom, ifrom + (int)Direction.Direc_Rank_L2r);
                            SetAttacks(color, pc, ifrom, ifrom + (int)Direction.Direc_Rank_R2l);
                            SetAttacks(color, pc, ifrom, ifrom + (int)Direction.Direc_Diag1_U2d);
                            SetAttacks(color, pc, ifrom, ifrom + (int)Direction.Direc_Diag2_U2d);
                            break;
                    }
                }
            }

            color = (int)Color.White;
            for (int pc = (int)Piece.Pawn; pc < Piece_NB; pc++)
            {
                for (int ifrom = 0; ifrom < Square_NB; ifrom++)
                {
                    switch (pc)
                    {
                        case (int)Piece.Pawn:
                            SetAttacks(color, pc, ifrom, ifrom + (int)Direction.Direc_File_U2d);
                            break;
                        case (int)Piece.Knight:
                            SetAttacks(color, pc, ifrom, ifrom + (int)Direction.Direc_Knight_L_U2d);
                            SetAttacks(color, pc, ifrom, ifrom + (int)Direction.Direc_Knight_R_U2d);
                            break;
                        case (int)Piece.Silver:
                            SetAttacks(color, pc, ifrom, ifrom + (int)Direction.Direc_File_U2d);
                            SetAttacks(color, pc, ifrom, ifrom + (int)Direction.Direc_Diag1_D2u);
                            SetAttacks(color, pc, ifrom, ifrom + (int)Direction.Direc_Diag2_D2u);
                            SetAttacks(color, pc, ifrom, ifrom + (int)Direction.Direc_Diag1_U2d);
                            SetAttacks(color, pc, ifrom, ifrom + (int)Direction.Direc_Diag2_U2d);
                            break;
                        case (int)Piece.Gold:
                        case (int)Piece.Pro_Pawn:
                        case (int)Piece.Pro_Lance:
                        case (int)Piece.Pro_Knight:
                        case (int)Piece.Pro_Silver:
                            SetAttacks(color, pc, ifrom, ifrom + (int)Direction.Direc_File_D2u);
                            SetAttacks(color, pc, ifrom, ifrom + (int)Direction.Direc_File_U2d);
                            SetAttacks(color, pc, ifrom, ifrom + (int)Direction.Direc_Diag1_U2d);
                            SetAttacks(color, pc, ifrom, ifrom + (int)Direction.Direc_Diag2_U2d);
                            SetAttacks(color, pc, ifrom, ifrom + (int)Direction.Direc_Rank_L2r);
                            SetAttacks(color, pc, ifrom, ifrom + (int)Direction.Direc_Rank_R2l);
                            break;
                        case (int)Piece.King:
                            SetAttacks(color, pc, ifrom, ifrom + (int)Direction.Direc_File_D2u);
                            SetAttacks(color, pc, ifrom, ifrom + (int)Direction.Direc_File_U2d);
                            SetAttacks(color, pc, ifrom, ifrom + (int)Direction.Direc_Diag1_D2u);
                            SetAttacks(color, pc, ifrom, ifrom + (int)Direction.Direc_Diag2_D2u);
                            SetAttacks(color, pc, ifrom, ifrom + (int)Direction.Direc_Rank_L2r);
                            SetAttacks(color, pc, ifrom, ifrom + (int)Direction.Direc_Rank_R2l);
                            SetAttacks(color, pc, ifrom, ifrom + (int)Direction.Direc_Diag1_U2d);
                            SetAttacks(color, pc, ifrom, ifrom + (int)Direction.Direc_Diag2_U2d);
                            break;
                    }
                }
            }
        }

        public static void SetAttacks(int color, int pc, int ifrom, int ito)
        {
            if (ifrom >= 0 && ifrom < Square_NB && ito >= 0 && ito < Square_NB)
            {
                if (pc == (int)Piece.Knight)
                {
                    int rd = Math.Abs(RankTable[ifrom] - RankTable[ito]);
                    if (rd != 2)
                        return;
                }
                else
                {
                    int rd = Math.Abs(RankTable[ifrom] - RankTable[ito]);
                    if (rd != 0 && rd != 1)
                        return;
                    int fd = Math.Abs(FileTable[ifrom] - FileTable[ito]);
                    if (fd != 0 && fd != 1)
                        return;
                }

                if (ifrom >= 0 && ifrom < Square_NB && ito >= 0 && ito < Square_NB)
                {
                    ABB_Piece_Attacks[color, pc, ifrom] |= ABB_Mask[ito];
                }
            }
        }

